'use client';
import { useState, useRef, useEffect } from 'react';
import { useChatStore } from '@/lib/store/chatStore';

export default function AiChatOverlay() {
  const { messages, isOpen, addMessage, setIsOpen } = useChatStore();
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    
    const userMsg = input.trim();
    setInput('');
    addMessage({ role: 'user', text: userMsg });
    setIsLoading(true);

    try {
      const response = await fetch(`/api/ai/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: userMsg, history: messages })
      });
      
      if (!response.ok) throw new Error("API Error");
      
      const data = await response.json();
      addMessage({ role: 'ai', text: data.reply || "Sorry, an error occurred while processing the response." });
    } catch (e) {
      console.error(e);
      addMessage({ role: 'ai', text: "Sorry, the AI system is currently experiencing issues. Try again later." });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end pointer-events-none" style={{zIndex: 9999}}>
      {isOpen && (
        <div className="mb-4 w-80 h-96 rounded-2xl border border-white/20 bg-black/60 backdrop-blur-xl p-4 flex flex-col shadow-[0_0_40px_rgba(0,0,0,0.5)] text-white pointer-events-auto transition-all duration-300 transform origin-bottom-right">
          <div className="flex justify-between items-center border-b border-white/10 pb-2 mb-2">
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              <h3 className="font-semibold text-lg font-sans">Bilal's Assistant</h3>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-white text-2xl leading-none transition-colors">&times;</button>
          </div>
          
          <div className="flex-1 overflow-y-auto text-sm space-y-3 font-sans pr-1 scrollbar-hide">
            {messages.map((msg, idx) => (
              <div key={idx} className={`p-3 rounded-lg inline-block max-w-[85%] ${msg.role === 'user' ? 'bg-[var(--accent-purple)] text-white self-end float-right clear-both rounded-br-none' : 'bg-white/10 text-gray-200 self-start float-left clear-both rounded-bl-none border border-white/5'}`}>
                {msg.text}
              </div>
            ))}
            {isLoading && (
              <div className="bg-white/10 p-3 rounded-lg self-start float-left clear-both inline-block opacity-70 border border-white/5 rounded-bl-none">
                <span className="flex gap-1">
                  <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></span>
                  <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></span>
                  <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></span>
                </span>
              </div>
            )}
            <div ref={messagesEndRef} className="clear-both" />
          </div>

          <div className="mt-3 flex gap-2 font-sans pt-3 border-t border-white/10">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask about Bilal..." 
              className="flex-1 bg-white/5 border border-white/10 rounded-lg px-3 py-2 outline-none text-white text-sm focus:border-[var(--accent-cyan)] focus:bg-white/10 transition-colors placeholder:text-gray-500"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className="bg-[var(--accent-cyan)] hover:bg-[var(--accent-purple)] disabled:opacity-50 disabled:hover:bg-[var(--accent-cyan)] px-4 py-2 rounded-lg text-sm transition-colors text-black hover:text-white font-medium shadow-lg"
            >
              Send
            </button>
          </div>
        </div>
      )}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`pointer-events-auto w-14 h-14 rounded-full backdrop-blur-md border border-white/20 shadow-[0_0_20px_rgba(var(--accent-cyan-rgb),0.3)] flex items-center justify-center transition-all duration-300 hover:scale-110 ${isOpen ? 'bg-[var(--accent-purple)] rotate-90' : 'bg-[var(--accent-cyan)] hover:bg-[var(--accent-purple)]'}`}
      >
        {isOpen ? (
          <span className="text-white text-2xl leading-none block transform -rotate-90">&times;</span>
        ) : (
          <span className="text-black text-2xl flex items-center justify-center">
            {/* Using an ion-icon or emoji for AI */}
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 8V4H8"/><rect width="16" height="12" x="4" y="8" rx="2"/><path d="M2 14h2"/><path d="M20 14h2"/><path d="M15 13v2"/><path d="M9 13v2"/></svg>
          </span>
        )}
      </button>
    </div>
  );
}
